class CloudAPIClient {
    static let shared = CloudAPIClient()
    private let baseURL = "https://api.example.com"
    private let httpClient = HTTPClient.shared
    
    private init() {}
    
    func getDevices(completion: @escaping (Result<[Device], HTTPClient.HTTPError>) -> Void) {
        let url = "\(baseURL)/devices"
        let headers = ["Authorization": "Bearer YOUR_TOKEN_HERE"]
        
        httpClient.request(url: url, method: .get, headers: headers, completion: completion)
    }
    
    func updateDevice(deviceId: String, data: DeviceUpdate, completion: @escaping (Result<Device, HTTPClient.HTTPError>) -> Void) {
        let url = "\(baseURL)/devices/\(deviceId)"
        let headers = ["Authorization": "Bearer YOUR_TOKEN_HERE"]
        
        httpClient.requestJSON(url: url, method: .put, headers: headers, body: data, completion: completion)
    }
    
    func createDevice(data: DeviceCreate, completion: @escaping (Result<Device, HTTPClient.HTTPError>) -> Void) {
        let url = "\(baseURL)/devices"
        let headers = ["Authorization": "Bearer YOUR_TOKEN_HERE"]
        
        httpClient.requestJSON(url: url, method: .post, headers: headers, body: data, completion: completion)
    }
}

